Javascript.validate:
			var errCode = null;
			var value = Services.getValue(this.dataBinding);
			if (!CaseManUtils.isBlank(value)) {
				if (!CaseManValidationHelper.validateFloatNumber(value))
				{
					errCode = ErrorCode.getErrorCode("CaseMan_Reports_Enter_Number");
				}
				if (value < 0)
				{
					errCode = ErrorCode.getErrorCode("CaseMan_Reports_Enter_Number");
				}
				//return CaseManValidationHelper.validatePattern(value, CaseManValidationHelper.NUMERIC_PATTERN, "CaseMan_Reports_Enter_Number");
			}

			return errCode;

Javascript.transformToDisplay:
// uct defect 268 - set the currency correctly
var returnValue = value;	
if(returnValue != null){
	if(returnValue != ""){
		var fVal = parseFloat(value).toFixed(2);
		
		if(!isNaN(fVal)){
			returnValue = CaseManUtils.isBlank(value) ? "" : fVal;
		}
	}	
}
return returnValue;

